/**
 * @name Zip Slip in JarFileUtils - ZipEntry name used in file construction without validation
 * @description ZipEntry names that contain path traversal sequences can escape the intended extraction directory
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip-jarfileutils
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Check if there's a call to getCanonicalPath or toRealPath nearby
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or
       mc.getMethod().hasName("toRealPath") or
       mc.getMethod().hasName("normalize")) and
      node.asExpr() = mc
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;
import ZipSlipFlow::PathGraph

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where ZipSlipFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Zip Slip: ZipEntry name $@ flows to file construction without path validation.",
  source.getNode(), "ZipEntry.getName()"

/**
 * @name Path traversal in SuiteRunner via output directory
 * @description SuiteRunner uses an output directory path that may flow to File construction without validation
 * @kind path-problem
 * @problem.severity error
 * @id java/suite-runner-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module SuiteRunnerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters to SuiteRunner constructors and init methods
    exists(Method m | 
      m.getDeclaringType().hasQualifiedName("org.testng", "SuiteRunner") and
      source.asParameter() = m.getAParameter() and
      source.asParameter().getType() instanceof TypeString
    )
    or
    exists(Constructor c |
      c.getDeclaringType().hasQualifiedName("org.testng", "SuiteRunner") and
      source.asParameter() = c.getAParameter() and
      source.asParameter().getType() instanceof TypeString
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor sinks
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileWriter/FileOutputStream sinks  
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileWriter") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module SuiteRunnerFlow = TaintTracking::Global<SuiteRunnerConfig>;
import SuiteRunnerFlow::PathGraph

from SuiteRunnerFlow::PathNode source, SuiteRunnerFlow::PathNode sink
where SuiteRunnerFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: SuiteRunner parameter $@ flows to file construction.", source.getNode(), "input"

/**
 * @name Path traversal via SuiteHTMLReporter output directory
 * @description The SuiteHTMLReporter uses user-controlled output directory without canonicalization
 * @kind path-problem
 * @problem.severity error
 * @id java/suite-html-reporter-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module SuiteHTMLReporterConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters of generateReport in SuiteHTMLReporter
    exists(Method m, Parameter p |
      m.getDeclaringType().hasQualifiedName("org.testng.reporters", "SuiteHTMLReporter") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructors
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileWriter/FileOutputStream
    exists(ClassInstanceExpr ce |
      (ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileWriter") or
       ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") or
       ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "PrintWriter")) and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module SuiteHTMLReporterFlow = TaintTracking::Global<SuiteHTMLReporterConfig>;
import SuiteHTMLReporterFlow::PathGraph

from SuiteHTMLReporterFlow::PathNode source, SuiteHTMLReporterFlow::PathNode sink
where SuiteHTMLReporterFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: SuiteHTMLReporter parameter $@ flows to file construction.", source.getNode(), "input"
